import React, { useEffect, useState } from "react";
import { Users, Apple, UserPlus, X, Mail, User as UserIcon } from "lucide-react";
import { supabase } from "./lib/supabase";

export function MembersPage({ onSelectMember }: { onSelectMember: (user: any) => void }) {
  const [members, setMembers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);

  // Estado para el nuevo atleta
  const [newAtleta, setNewAtleta] = useState({
    first_name: '',
    last_name: '',
    email: '',
    role: 'client'
  });

  const fetchMembers = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('profiles')
      .select('*')
      .order('created_at', { ascending: false });

    if (!error && data) setMembers(data);
    setLoading(false);
  };

  useEffect(() => {
    fetchMembers();
  }, []);

  const handleAddAtleta = async (e: React.FormEvent) => {
    e.preventDefault();

    // 1. Creamos el perfil en la tabla public.profiles
    // Nota: En un entorno real, primero crearías el usuario en Auth, 
    // pero para probar la interfaz, lo insertaremos directamente en profiles.
    const { error } = await supabase
      .from('profiles')
      .insert([
        { 
          id: crypto.randomUUID(), // Generamos un ID temporal
          first_name: newAtleta.first_name,
          last_name: newAtleta.last_name,
          full_name: `${newAtleta.first_name.toLowerCase()}${newAtleta.last_name.toLowerCase()}`,
          role: newAtleta.role
        }
      ]);

    if (error) {
      alert("Error al añadir: " + error.message);
    } else {
      setShowAddModal(false);
      setNewAtleta({ first_name: '', last_name: '', email: '', role: 'client' });
      fetchMembers(); // Recargar lista
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Atletas</h1>
          <p className="text-gray-400 mt-1">Gestión de la base de datos de miembros</p>
        </div>
        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-[#39FF14] text-[#121212] px-6 py-3 rounded-lg font-bold hover:bg-[#2EE010] transition-all flex items-center gap-2 shadow-[0_0_15px_rgba(57,255,20,0.3)]"
        >
          <UserPlus className="w-5 h-5" />
          Añadir Atleta
        </button>
      </div>

      {/* Tabla (Mismo diseño que ya tienes) */}
      <div className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-[#121212] border-b border-[#2a2a2a] text-gray-400 text-xs uppercase">
            <tr>
              <th className="p-4">Cliente</th>
              <th className="p-4">Estado</th>
              <th className="p-4 text-right">Acciones</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-[#2a2a2a]">
            {members.map((member) => (
              <tr key={member.id} className="hover:bg-white/5 transition-colors">
                <td className="p-4 flex items-center gap-3">
                  <div className="w-10 h-10 bg-[#39FF14]/10 rounded-full flex items-center justify-center text-[#39FF14] font-bold border border-[#39FF14]/20">
                    {member.first_name?.[0]}
                  </div>
                  <div>
                    <p className="font-bold text-white">{member.first_name} {member.last_name}</p>
                    <p className="text-xs text-zinc-500 font-mono">{member.id.substring(0,8)}...</p>
                  </div>
                </td>
                <td className="p-4">
                  <span className="px-3 py-1 bg-blue-500/10 text-blue-400 border border-blue-500/20 rounded-full text-[10px] font-bold uppercase">
                    {member.role || 'Cliente'}
                  </span>
                </td>
                <td className="p-4 text-right">
                  <button 
                    onClick={() => onSelectMember(member)}
                    className="bg-[#121212] border border-[#2a2a2a] text-[#39FF14] px-4 py-2 rounded-lg text-sm font-bold hover:bg-[#39FF14] hover:text-black transition-all flex items-center gap-2 ml-auto"
                  >
                    <Apple size={14} /> Plan Nutricional
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* MODAL PARA AÑADIR ATLETA */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[150] flex items-center justify-center p-4">
          <div className="bg-[#1a1a1a] border border-[#2a2a2a] w-full max-w-md rounded-2xl p-8 shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-white">Registrar Nuevo Cliente</h2>
              <button onClick={() => setShowAddModal(false)} className="text-gray-400 hover:text-white">
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleAddAtleta} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold">Nombre</label>
                  <input 
                    required
                    className="w-full bg-[#121212] border border-[#2a2a2a] p-3 rounded-xl mt-1 text-white focus:border-[#39FF14] outline-none"
                    placeholder="Ej: Juan"
                    value={newAtleta.first_name}
                    onChange={(e) => setNewAtleta({...newAtleta, first_name: e.target.value})}
                  />
                </div>
                <div>
                  <label className="text-xs text-gray-500 uppercase font-bold">Apellido</label>
                  <input 
                    required
                    className="w-full bg-[#121212] border border-[#2a2a2a] p-3 rounded-xl mt-1 text-white focus:border-[#39FF14] outline-none"
                    placeholder="Ej: Pérez"
                    value={newAtleta.last_name}
                    onChange={(e) => setNewAtleta({...newAtleta, last_name: e.target.value})}
                  />
                </div>
              </div>

              <div>
                <label className="text-xs text-gray-500 uppercase font-bold">Correo Electrónico</label>
                <div className="relative">
                  <Mail className="absolute left-3 top-4 text-gray-600" size={18} />
                  <input 
                    type="email"
                    className="w-full bg-[#121212] border border-[#2a2a2a] p-3 pl-10 rounded-xl mt-1 text-white focus:border-[#39FF14] outline-none"
                    placeholder="atleta@correo.com"
                    value={newAtleta.email}
                    onChange={(e) => setNewAtleta({...newAtleta, email: e.target.value})}
                  />
                </div>
              </div>

              <div>
                <label className="text-xs text-gray-500 uppercase font-bold">Rol del Miembro</label>
                <select 
                  className="w-full bg-[#121212] border border-[#2a2a2a] p-3 rounded-xl mt-1 text-white outline-none focus:border-[#39FF14]"
                  value={newAtleta.role}
                  onChange={(e) => setNewAtleta({...newAtleta, role: e.target.value})}
                >
                  <option value="client">Cliente</option>
                  <option value="trainer">Entrenador</option>
                  <option value="admin">Administrador</option>
                </select>
              </div>

              <div className="pt-4 flex gap-3">
                <button 
                  type="button"
                  onClick={() => setShowAddModal(false)}
                  className="flex-1 px-4 py-3 bg-[#121212] border border-[#2a2a2a] rounded-xl text-gray-400 font-bold hover:bg-zinc-800 transition-colors"
                >
                  Cancelar
                </button>
                <button 
                  type="submit"
                  className="flex-1 px-4 py-3 bg-[#39FF14] text-black rounded-xl font-bold hover:bg-[#2EE010] transition-all"
                >
                  Guardar Cliente
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
